// Place global declarations here.
clock globalTime;
const int INFINITE_TIME = -1;
const int INF = INFINITE_TIME;
const int N_REACTANTS = 12;
broadcast chan reached[N_REACTANTS];
broadcast chan reaching, do_update;


typedef struct {
	int[-99980001, 99980001] b;
	int e;
} double_t;

const double_t zero = {0, 0};
const double_t INFINITE_TIME_DOUBLE = {-1000, -3}; //INFINITE_TIME (-1) translated into double
//R0 = (1)
int R0 := 1;
const int R0Levels := 1;
const double_t R0Levels_d := {1000, -3};

//R1 = (2)
int R1 := 1;
const int R1Levels := 1;
const double_t R1Levels_d := {1000, -3};

//R2 = (3)
int R2 := 1;
const int R2Levels := 1;
const double_t R2Levels_d := {1000, -3};

//R3 = EGF
int R3 := 15;
const int R3Levels := 15;
const double_t R3Levels_d := {1500, -2};

//R4 = ERK
int R4 := 0;
const int R4Levels := 100;
const double_t R4Levels_d := {1000, -1};

//R5 = MEK
int R5 := 0;
const int R5Levels := 60;
const double_t R5Levels_d := {6000, -2};

//R6 = NGF
int R6 := 0;
const int R6Levels := 15;
const double_t R6Levels_d := {1500, -2};

//R7 = PKC
int R7 := 0;
const int R7Levels := 40;
const double_t R7Levels_d := {4000, -2};

//R8 = RAF
int R8 := 0;
const int R8Levels := 60;
const double_t R8Levels_d := {6000, -2};

//R9 = RKIP
int R9 := 20;
const int R9Levels := 20;
const double_t R9Levels_d := {2000, -2};

//R10 = introduction of Ab
int R10 := 1;
const int R10Levels := 1;
const double_t R10Levels_d := {1000, -3};

//R11 = neutralizing antibody
int R11 := 0;
const int R11Levels := 1;
const double_t R11Levels_d := {1000, -3};


typedef int[-1, 1073741822] time_t;
typedef int[-1073741822, 1073741822] int_t;

typedef struct {
	time_t T;
} timeActivity;

//Reaction R9 (RKIP) --| R8 (RAF)
timeActivity R9_R8;
const double_t k_R9_R8 = {1333, -10};

//Reaction R8 (RAF) --> R5 (MEK)
timeActivity R8_R5;
const double_t k_R8_R5 = {2222, -10};

//Reaction R5 (MEK) --> R4 (ERK)
timeActivity R5_R4;
const double_t k_R5_R4 = {1667, -10};

//Reaction R11 (neutralizing antibody) --| R6 (NGF)
timeActivity R11_R6;
const double_t k_R11_R6 = {1000, -9};

//Reaction R10 (introduction of Ab) --> R11 (neutralizing antibody)
timeActivity R10_R11;
const double_t k_R10_R11 = {7780, -10};

//Reaction R3 (EGF) --> R8 (RAF)
timeActivity R3_R8;
const double_t k_R3_R8 = {1778, -10};

//Reaction R1 ((2)) --| R5 (MEK)
timeActivity R1_R5;
const double_t k_R1_R5 = {1000, -9};

//Reaction R11 (neutralizing antibody) --| R3 (EGF)
timeActivity R11_R3;
const double_t k_R11_R3 = {1667, -8};

//Reaction R2 ((3)) --| R4 (ERK)
timeActivity R2_R4;
const double_t k_R2_R4 = {1000, -9};

//Reaction R6 (NGF) --> R8 (RAF)
timeActivity R6_R8;
const double_t k_R6_R8 = {8890, -11};

//Reaction R4 (ERK) --| R5 (MEK)
timeActivity R4_R5;
const double_t k_R4_R5 = {5000, -11};

//Reaction R7 (PKC) --| R9 (RKIP)
timeActivity R7_R9;
const double_t k_R7_R9 = {3330, -11};

//Reaction R6 (NGF) --> R7 (PKC)
timeActivity R6_R7;
const double_t k_R6_R7 = {1185, -11};

//Reaction R4 (ERK) AND R7 (PKC) --> R8 (RAF)
timeActivity R4_R7_R8;
const double_t k_R4_R7_R8 = {1667, -12};

//Reaction R7 (PKC) --> R8 (RAF)
timeActivity R7_R8;
const double_t k_R7_R8 = {0, -6};

//Reaction R0 ((1)) --| R8 (RAF)
timeActivity R0_R8;
const double_t k_R0_R8 = {8330, -10};



double_t subtract(double_t a, double_t b) { // a - b
	double_t r = {-1000, -1000};
	if (a.b == 0) {
		r.b = -b.b;
		r.e = b.e;
		return r;
	}
	if (b.b == 0) {
		return a;
	}
	if ((a.e - b.e) >= 4) return a;
	if ((b.e - a.e) >= 4) {
		r.b = -b.b;
		r.e = b.e;
		return r;
	}
	if (a.e == b.e) {
		r.b = a.b - b.b;
		r.e = a.e;
	}
	if (a.e - b.e == 1) {
		r.b = a.b - b.b/10;
		r.e = a.e;
	}
	if (a.e - b.e == 2) {
		r.b = a.b - b.b/100;
		r.e = a.e;
	}
	if (a.e - b.e == 3) {
		r.b = a.b - b.b/1000;
		r.e = a.e;
	}
	if (b.e - a.e == 1) {
		r.b = a.b/10 - b.b;
		r.e = b.e;
	}
	if (b.e - a.e == 2) {
		r.b = a.b/100 - b.b;
		r.e = b.e;
	}
	if (b.e - a.e == 3) {
		r.b = a.b/1000 - b.b;
		r.e = b.e;
	}
	if ((r.b > 0 && r.b < 10) || (r.b < 0 && r.b > -10)) {
		r.b = r.b * 1000;
		r.e = r.e - 3;
	} else if ((r.b > 0 && r.b < 100) || (r.b < 0 && r.b > -100)) {
		r.b = r.b * 100;
		r.e = r.e - 2;
	} else if ((r.b > 0 && r.b < 1000) || (r.b < 0 && r.b > -1000)) {
		r.b = r.b * 10;
		r.e = r.e - 1;
	} else if (r.b > 9999 || r.b < -9999) {
		r.b = r.b / 10;
		r.e = r.e + 1;
	}
	return r;
}

double_t add(double_t a, double_t b) { // a + b
	double_t r = {-1000,-1000};
	if (a.b == 0) {
		return b;
	}
	if (b.b == 0) {
		return a;
	}
	if ((a.e - b.e) >= 4) return a;
	if ((b.e - a.e) >= 4) return b;
	if (a.e == b.e) {
		r.b = a.b + b.b;
		r.e = a.e;
	}
	if (a.e - b.e == 1) {
		r.b = a.b + b.b/10;
		r.e = a.e;
	}
	if (a.e - b.e == 2) {
		r.b = a.b + b.b/100;
		r.e = a.e;
	}
	if (a.e - b.e == 3) {
		r.b = a.b + b.b/1000;
		r.e = a.e;
	}
	if (b.e - a.e == 1) {
		r.b = a.b/10 + b.b;
		r.e = b.e;
	}
	if (b.e - a.e == 2) {
		r.b = a.b/100 + b.b;
		r.e = b.e;
	}
	if (b.e - a.e == 3) {
		r.b = a.b/1000 + b.b;
		r.e = b.e;
	}
	if ((r.b > 0 && r.b < 10) || (r.b < 0 && r.b > -10)) {
		r.b = r.b * 1000;
		r.e = r.e - 3;
	} else if ((r.b > 0 && r.b < 100) || (r.b < 0 && r.b > -100)) {
		r.b = r.b * 100;
		r.e = r.e - 2;
	} else if ((r.b > 0 && r.b < 1000) || (r.b < 0 && r.b > -1000)) {
		r.b = r.b * 10;
		r.e = r.e - 1;
	} else if (r.b > 9999 || r.b < -9999) {
		r.b = r.b / 10;
		r.e = r.e + 1;
	}
	return r;
}

double_t multiply(double_t a, double_t b) { // a * b
	double_t r;
	r.b = a.b * b.b;
	if (r.b % 1000 < 500) {
		r.b = r.b / 1000;
	} else {
		r.b = 1 + r.b / 1000;
	}
	r.e = a.e + b.e + 3;
	if ((r.b > 0 && r.b < 10) || (r.b < 0 && r.b > -10)) {
		r.b = r.b * 1000;
		r.e = r.e - 3;
	} else if ((r.b > 0 && r.b < 100) || (r.b < 0 && r.b > -100)) {
		r.b = r.b * 100;
		r.e = r.e - 2;
	} else if ((r.b > 0 && r.b < 1000) || (r.b < 0 && r.b > -1000)) {
		r.b = r.b * 10;
		r.e = r.e - 1;
	}
	while (r.b > 9999 || r.b < -9999) {
		r.b = r.b / 10;
		r.e = r.e + 1;
	}
	return r;
}

double_t divide(double_t a, double_t b) { //a / b
	double_t r;
	if (b.b == 0) {
		return INFINITE_TIME_DOUBLE;
	}
	r.b = a.b * 1000 / b.b;
	r.e = a.e - b.e - 3;
	if (r.b == 0) {
		return r;
	}
	while (r.b < 9999 && r.b > -9999) {
		r.b = r.b * 10;
		r.e = r.e -1;
	}
	while (r.b > 9999 || r.b < -9999) {
		r.b = r.b / 10;
		r.e = r.e + 1;
	}
	return r;
}

double_t inverse(double_t a) { // 1 / a
	double_t r;
	if (a.b == 0) {
		return INFINITE_TIME_DOUBLE;
	}
	if (a.e < -12) { // 1 / 1e-9 is still ok, but 1 / 1e-10 is too large (> 2^30 - 2, the largest allowed constant for guards/invariants)
		r.b = 1073;
		r.e = 6;
		return r;
	}
	r.b = 10000000 / a.b;
	r.e = -7 - a.e;
	if ((r.b > 0 && r.b < 10) || (r.b < 0 && r.b > -10)) {
		r.b = r.b * 1000;
		r.e = r.e - 3;
	} else if ((r.b > 0 && r.b < 100) || (r.b < 0 && r.b > -100)) {
		r.b = r.b * 100;
		r.e = r.e - 2;
	} else if ((r.b > 0 && r.b < 1000) || (r.b < 0 && r.b > -1000)) {
		r.b = r.b * 10;
		r.e = r.e - 1;
	}
	return r;
}

time_t power(int a, int b) { // a ^ b (b >= 0)
	time_t r = 1;
	while (b > 0) {
		r = r * a;
		b = b - 1;
	}
	return r;
}

int_t _ANIMO_round(double_t a) { // double --> integer
	if (a == INFINITE_TIME_DOUBLE) { // Don't need to translate literally if we have infinite
		return INFINITE_TIME;
	}
	if (a.b >= 1073 && a.e >= 6) { // If the number is too large, we consider it to be infinite
		return INFINITE_TIME;
	}
	if (a.e < -4) {
		return 0;
	}
	if (a.e == -1) {
		if (a.b % 10 < 5) {
			return a.b / 10;
		} else {
			return 1 + a.b / 10;
		}
	}
	if (a.e == -2) {
		if (a.b % 100 < 50) {
			return a.b / 100;
		} else {
			return 1 + a.b / 100;
		}
	}
	if (a.e == -3) {
		if (a.b % 1000 < 500) {
			return a.b / 1000;
		} else {
			return 1 + a.b / 1000;
		}
	}
	if (a.e == -4) {
		if (a.b < 5000) return 0;
		else return 1;
	}
	return a.b * power(10, a.e);
}

double_t scenario1(double_t k, double_t r1, double_t r1Levels, bool r1Active) {
	double_t E;
	if (r1Active) { //If we depend on active R1, the level of activity is the value of E
		E = r1;
	} else { //otherwise we find the inactivity level via the total number of levels
		E = subtract(r1Levels, r1);
	}
	return multiply(k, E);
}


double_t scenario2_3(double_t k, double_t r2, double_t r2Levels, bool r2Active, double_t r1, double_t r1Levels, bool r1Active) {
	double_t E, S;
	if (r1Active) { //If we depend on active R1, the level of activity is the value of E
		E = r1;
	} else { //otherwise we find the inactivity level via the total number of levels
		E = subtract(r1Levels, r1);
	}
	if (r2Active) { //Same for R2
		S = r2;
	} else {
		S = subtract(r2Levels, r2);
	}
	return multiply(k, multiply(E, S));
}


double_t int_to_double(int_t a) { //Used to translate an activity level into double.
	double_t r;
	bool neg = false;
	if (a < 0) {
		a = -a;
		neg = true;
	}
	if (a < 10) {
		r.b = a * 1000;
		r.e = -3;
	} else if (a < 100) {
		r.b = a * 100;
		r.e = -2;
	} else if (a < 1000) {
		r.b = a * 10;
		r.e = -1;
	} else if (a < 10000) { //Our model supports up to 100 levels, so this should be the most it makes sense to check
		r.b = a;
		r.e = 0;
	} else {
		r.e = 0;
		while (a > 9999) {
			a = a / 10;
			r.e++;
		}
		r.b = a;
	}
	if (neg) {
		r.b = -r.b;
	}
	return r;
}

template.declaration:
int[-1, 1] delta = 0;
time_t TL, TU;
clock c;
double_t totalRate = INFINITE_TIME_DOUBLE, oldRate = INFINITE_TIME_DOUBLE;


double_t compute_rate() {
	double_t R11_R3_r = scenario2_3(k_R11_R3, int_to_double(R3), int_to_double(R3Levels), true, int_to_double(R11), int_to_double(R11Levels), true);
	if (R11_R3_r.b == 0 && R11 > 0) { //If the downstream reactant (R) is the only reason for the inactivity of the reaction R11_R3 (note that R is actually R3), consider the reaction as still available (recomputing the rate as the one closest to the current situation), to avoid significant errors in performing the next update to R. We want to avoid considering any other reaction active on R as the only one possible during the whole next delta increment to R.
		//Using the following rate is not very precise, but makes for a much more precise total rate than we would get if considering the reaction as inactive (especially with low levels of granularity for R, i.e. small values of MAX)
		R11_R3_r = scenario2_3(k_R11_R3, int_to_double(1), int_to_double(R3Levels), true, int_to_double(R11), int_to_double(R11Levels), true);
	}
	//R11_R3.T = _ANIMO_round(inverse(R11_R3_r));
	return subtract(zero, R11_R3_r);
}

void update() {
	oldRate = totalRate;
	totalRate = compute_rate();
	if (totalRate.b < 0) {
		delta = -1;
		totalRate.b = -totalRate.b;
	} else {
		delta = 1;
	}
	if (totalRate.b != 0) {
		TL = _ANIMO_round(inverse(totalRate));
		TU = TL;
		if (TL < 1) TL = 1; // Ensure that the minimal duration for a reaction is 1 t.u., otherwise the model will behave nondeterministically
		if (TU < 1) TU = 1;
	} else {
		TL = INFINITE_TIME;
		TU = INFINITE_TIME;
	}
	if (TL != INFINITE_TIME && TL > TU) { //We use rounded things: maybe the difference between TL and TU was not so large, and with some rounding problems we could have this case
		TL = TU;
	}
	if ((delta >= 0 && R == MAX) || (delta < 0 && R == 0)) {
		TL = TU = INFINITE_TIME;
	}
}

void reach() {
	if (-MAX <= R + delta && R + delta <= MAX) {
		R = R + delta;
	}
}

void make_urgent() {
	c = 0;
	TU = 0;
	TL = 0;
}

bool rate_significantly_changed(double_t oldRate, double_t newRate) { //True if the new rate is at least double the old one, or if the sign of the rates is different (the reaction changes direction. Note that no change of direction will be detected if we are at MAX or 0, or we were constant until now)
	if ((oldRate.b < 0 && newRate.b > 0 || oldRate.b > 0 && newRate.b < 0) && (R < MAX && R > 0)) {
		return true;
	}
	return false;
}

void decide_reset() {
	if (rate_significantly_changed(oldRate, totalRate)) { //If the updated conditions have significantly changed the rate, restart the reaction from the beginning, without considering the work already done.
		c = 0;
	}
}

bool infinite_delay() {
	return TU == INFINITE_TIME;
}

int[-1, 1] delta = 0;
time_t TL, TU;
clock c;
double_t totalRate = INFINITE_TIME_DOUBLE, oldRate = INFINITE_TIME_DOUBLE;


double_t compute_rate() {
	double_t R5_R4_r = scenario2_3(k_R5_R4, int_to_double(R4), int_to_double(R4Levels), false, int_to_double(R5), int_to_double(R5Levels), true);
	double_t R2_R4_r = scenario2_3(k_R2_R4, int_to_double(R4), int_to_double(R4Levels), true, int_to_double(R2), int_to_double(R2Levels), true);
	if (R5_R4_r.b == 0 && R5 > 0) { //If the downstream reactant (R) is the only reason for the inactivity of the reaction R5_R4 (note that R is actually R4), consider the reaction as still available (recomputing the rate as the one closest to the current situation), to avoid significant errors in performing the next update to R. We want to avoid considering any other reaction active on R as the only one possible during the whole next delta increment to R.
		//Using the following rate is not very precise, but makes for a much more precise total rate than we would get if considering the reaction as inactive (especially with low levels of granularity for R, i.e. small values of MAX)
		R5_R4_r = scenario2_3(k_R5_R4, int_to_double(R4Levels - 1), int_to_double(R4Levels), false, int_to_double(R5), int_to_double(R5Levels), true);
	}
	if (R2_R4_r.b == 0 && R2 > 0) { //If the downstream reactant (R) is the only reason for the inactivity of the reaction R2_R4 (note that R is actually R4), consider the reaction as still available (recomputing the rate as the one closest to the current situation), to avoid significant errors in performing the next update to R. We want to avoid considering any other reaction active on R as the only one possible during the whole next delta increment to R.
		//Using the following rate is not very precise, but makes for a much more precise total rate than we would get if considering the reaction as inactive (especially with low levels of granularity for R, i.e. small values of MAX)
		R2_R4_r = scenario2_3(k_R2_R4, int_to_double(1), int_to_double(R4Levels), true, int_to_double(R2), int_to_double(R2Levels), true);
	}
	//R5_R4.T = _ANIMO_round(inverse(R5_R4_r));
	//R2_R4.T = _ANIMO_round(inverse(R2_R4_r));
	return subtract(add(zero, R5_R4_r), R2_R4_r);
}

void update() {
	oldRate = totalRate;
	totalRate = compute_rate();
	if (totalRate.b < 0) {
		delta = -1;
		totalRate.b = -totalRate.b;
	} else {
		delta = 1;
	}
	if (totalRate.b != 0) {
		TL = _ANIMO_round(inverse(totalRate));
		TU = TL;
		if (TL < 1) TL = 1; // Ensure that the minimal duration for a reaction is 1 t.u., otherwise the model will behave nondeterministically
		if (TU < 1) TU = 1;
	} else {
		TL = INFINITE_TIME;
		TU = INFINITE_TIME;
	}
	if (TL != INFINITE_TIME && TL > TU) { //We use rounded things: maybe the difference between TL and TU was not so large, and with some rounding problems we could have this case
		TL = TU;
	}
	if ((delta >= 0 && R == MAX) || (delta < 0 && R == 0)) {
		TL = TU = INFINITE_TIME;
	}
}

void reach() {
	if (-MAX <= R + delta && R + delta <= MAX) {
		R = R + delta;
	}
}

void make_urgent() {
	c = 0;
	TU = 0;
	TL = 0;
}

bool rate_significantly_changed(double_t oldRate, double_t newRate) { //True if the new rate is at least double the old one, or if the sign of the rates is different (the reaction changes direction. Note that no change of direction will be detected if we are at MAX or 0, or we were constant until now)
	if ((oldRate.b < 0 && newRate.b > 0 || oldRate.b > 0 && newRate.b < 0) && (R < MAX && R > 0)) {
		return true;
	}
	return false;
}

void decide_reset() {
	if (rate_significantly_changed(oldRate, totalRate)) { //If the updated conditions have significantly changed the rate, restart the reaction from the beginning, without considering the work already done.
		c = 0;
	}
}

bool infinite_delay() {
	return TU == INFINITE_TIME;
}

int[-1, 1] delta = 0;
time_t TL, TU;
clock c;
double_t totalRate = INFINITE_TIME_DOUBLE, oldRate = INFINITE_TIME_DOUBLE;


double_t compute_rate() {
	double_t R8_R5_r = scenario2_3(k_R8_R5, int_to_double(R5), int_to_double(R5Levels), false, int_to_double(R8), int_to_double(R8Levels), true);
	double_t R1_R5_r = scenario2_3(k_R1_R5, int_to_double(R5), int_to_double(R5Levels), true, int_to_double(R1), int_to_double(R1Levels), true);
	double_t R4_R5_r = scenario2_3(k_R4_R5, int_to_double(R5), int_to_double(R5Levels), true, int_to_double(R4), int_to_double(R4Levels), true);
	if (R8_R5_r.b == 0 && R8 > 0) { //If the downstream reactant (R) is the only reason for the inactivity of the reaction R8_R5 (note that R is actually R5), consider the reaction as still available (recomputing the rate as the one closest to the current situation), to avoid significant errors in performing the next update to R. We want to avoid considering any other reaction active on R as the only one possible during the whole next delta increment to R.
		//Using the following rate is not very precise, but makes for a much more precise total rate than we would get if considering the reaction as inactive (especially with low levels of granularity for R, i.e. small values of MAX)
		R8_R5_r = scenario2_3(k_R8_R5, int_to_double(R5Levels - 1), int_to_double(R5Levels), false, int_to_double(R8), int_to_double(R8Levels), true);
	}
	if (R1_R5_r.b == 0 && R1 > 0) { //If the downstream reactant (R) is the only reason for the inactivity of the reaction R1_R5 (note that R is actually R5), consider the reaction as still available (recomputing the rate as the one closest to the current situation), to avoid significant errors in performing the next update to R. We want to avoid considering any other reaction active on R as the only one possible during the whole next delta increment to R.
